import SwiftUI
import Combine

class TradeViewModel: ObservableObject {
    @Published var stocks: [Stock] = []
    @Published var portfolio: Portfolio = Portfolio()
    private let apiService: APIService = APIService()

    func fetchStocks() {
        apiService.fetchStocks { stocks in
            self.stocks = stocks
        }
    }

    func executeTrade(stock: Stock, quantity: Int) {
        apiService.executeTrade(stock: stock, quantity: quantity) { result in
            switch result {
            case .success(let transaction):
                self.portfolio.addTransaction(transaction)
            case .failure(let error):
                print(error)
            }
        }
    }
}

struct TradeView: View {
    @ObservedObject var viewModel: TradeViewModel

    var body: some View {
        List(viewModel.stocks) { stock in
            TradeRow(stock: stock, viewModel: viewModel)
        }
        .onAppear {
            viewModel.fetchStocks()
        }
    }
}

struct TradeRow: View {
    let stock: Stock
    @ObservedObject var viewModel: TradeViewModel

    var body: some View {
        HStack {
            Text(stock.symbol)
            Text(String(stock.price))
            Button("Buy") {
                viewModel.executeTrade(stock: stock, quantity: 1)
            }
        }
    }
}

